@function_tool
def trigger_crawler_flaresolverr(url_to_crawl: str, seed_id: Optional[int] = None, auto_create: bool = True) -> str:
    """
    啟動 FlareSolverr 爬蟲對指定 URL 進行深度抓取。
    
    參數:
        url_to_crawl: 要抓取的網址。
        seed_id: 關聯的種子 ID (可選)。
        auto_create: 是否自動創建發現的資產。
    """
    url = f"{API_BASE_URL}/flaresolverr/start_scanner"
    payload = {"url": url_to_crawl, "seed_id": seed_id, "method": "GET", "auto_create": auto_create}
    try:
        response = requests.post(url, json=payload)
        response.raise_for_status()
        return json.dumps(response.json(), indent=2, ensure_ascii=False)
    except Exception as e:
        return f"錯誤: {str(e)}"

